from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismAddIntegrationNode(BaseNode):
    name = "Prism: Add DCC Integration"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("mode", "string", widget_type="dropdown", options=["specific","all"], default="specific")
        self.add_input("dcc_name", "string", widget_type="text", default="Maya")
        self.add_input("dcc_prefs_path", "string", widget_type="file")
        self.add_output("success", "bool")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        mode = inputs.get('mode') or 'specific'
        dcc = inputs.get('dcc_name') or ''
        path = inputs.get('dcc_prefs_path') or ''
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and run it before this node (connect its exec_out to this node's exec_in).")
            return {'success': False, 'exec_out': True}
        try:
            if mode == 'all':
                core.integration.addAllIntegrations()
                self.log_success("Added all DCC integrations.")
            else:
                if not dcc or not path:
                    self.log_error("Need dcc_name and dcc_prefs_path for 'specific' mode.")
                    return {'success': False}
                core.integration.addIntegration(dcc, path)
                self.log_success(f"Added integration: {dcc} -> {path}")
            await self.set_output('exec_out', True)
            return {'success': True}
        except Exception as e:
            self.log_error(f"addIntegration failed: {e}")
            return {'success': False}

def register_node():
    return PrismAddIntegrationNode
